import{_ as a,o as t,c as r,ai as i,aj as o}from"./chunks/framework.DG6aArJf.js";const m=JSON.parse('{"title":"The Creator","description":"","frontmatter":{},"headers":[],"relativePath":"creator/creator.md","filePath":"creator/creator.md"}'),n={name:"creator/creator.md"};function l(s,e,h,p,c,d){return t(),r("div",null,[...e[0]||(e[0]=[i('<p><a href="https://github.com/sponsors/giovanni1707" target="_blank" rel="noreferrer"><img src="https://img.shields.io/badge/Sponsor-%F0%9F%92%96-pink" alt="Sponsor"></a></p><p><a href="https://paypal.me/GiovanniSylvain" target="_blank" rel="noreferrer"><img src="https://img.shields.io/badge/Sponsor-PayPal-blue?logo=paypal" alt="Sponsor"></a></p><h1 id="the-creator" tabindex="-1">The Creator <a class="header-anchor" href="#the-creator" aria-label="Permalink to “The Creator”">​</a></h1><div class="creator"><img src="'+o+'" alt="Giovanni Marianne" class="creator-photo"><div class="creator-info"><p><strong>Giovanni Marianne</strong></p><p>Creator of DOM Helpers Library</p></div></div><h2 id="origins-a-vanilla-javascript-passion" tabindex="-1">Origins: A Vanilla JavaScript Passion <a class="header-anchor" href="#origins-a-vanilla-javascript-passion" aria-label="Permalink to “Origins: A Vanilla JavaScript Passion”">​</a></h2><p>DOM Helpers Core was born from a deep passion for Vanilla JavaScript and a desire to preserve a direct, hands-on relationship with the DOM. My journey began with exploring modern frameworks like React and Vue.js—powerful tools that have transformed the way we build web applications.</p><p>Over time, I realized that what truly drew me to these frameworks was not the abstraction itself, but one core idea above all else: reactivity. However, as I went deeper into framework-driven development, I slowly began to lose my connection with plain Vanilla JavaScript.</p><p>Working behind layers of abstraction distanced me from how the DOM actually works. Native Web APIs started to feel unfamiliar, and fundamental concepts were no longer part of my day-to-day thinking. Instead of strengthening my understanding of the platform, too much was being abstracted away from it.</p><h3 id="the-framework-dilemma" tabindex="-1">The Framework Dilemma <a class="header-anchor" href="#the-framework-dilemma" aria-label="Permalink to “The Framework Dilemma”">​</a></h3><p>While frameworks provided incredible reactivity, they came with costs that grew harder to ignore:</p><p><strong>The Abstraction Problem:</strong></p><ul><li>Too much magic happening behind the scenes</li><li>DOM manipulation hidden away from view</li><li>The real mechanics of the DOM became distant and abstract</li><li>Skills for direct DOM manipulation began to fade</li></ul><p><strong>The Spoon-Feeding Effect:</strong></p><ul><li>Less logical understanding of what was actually happening</li><li>Heavy abstractions that obscured fundamental JavaScript</li><li>Gradual forgetting of how to truly work with the DOM</li><li>Dependency on framework-specific patterns</li></ul><p><strong>The Lost Connection:</strong> Working with the DOM in the vanilla way was more exciting—it provided clarity, control, and deep understanding. Every action was intentional. Every result was traceable. JavaScript skills were constantly strengthened through direct manipulation. But there was one critical challenge: <strong>keeping the UI in sync with state changes.</strong></p><h3 id="the-realization" tabindex="-1">The Realization <a class="header-anchor" href="#the-realization" aria-label="Permalink to “The Realization”">​</a></h3><p>This synchronization problem—and <em>only</em> this problem—was what made frameworks necessary. Everything else about vanilla JavaScript development felt right. The question became clear:</p><blockquote><p><strong>What if we could solve just this one problem without sacrificing everything else?</strong></p></blockquote><h3 id="the-vision" tabindex="-1">The Vision <a class="header-anchor" href="#the-vision" aria-label="Permalink to “The Vision”">​</a></h3><p>The creator envisioned a solution that would:</p><p>✅ <strong>Provide reactivity without abstraction</strong><br> ✅ <strong>Integrate into any project structure</strong><br> ✅ <strong>Preserve direct DOM manipulation</strong><br> ✅ <strong>Strengthen JavaScript fundamentals</strong><br> ✅ <strong>Work with any coding style</strong></p><p>The result: <strong>DOM Helpers Reactive</strong>—a plug-and-play reactivity system that adapts to you, not the other way around.</p><h2 id="design-philosophy" tabindex="-1">Design Philosophy <a class="header-anchor" href="#design-philosophy" aria-label="Permalink to “Design Philosophy”">​</a></h2><h3 id="plug-and-play-not-restructure" tabindex="-1">Plug and Play, Not Restructure <a class="header-anchor" href="#plug-and-play-not-restructure" aria-label="Permalink to “Plug and Play, Not Restructure”">​</a></h3><p>Unlike frameworks that demand architectural compliance, DOM Helpers Reactive simply slots into existing projects:</p><ul><li><strong>Plain JavaScript project?</strong> Load the script tag. Play with reactivity.</li><li><strong>jQuery codebase?</strong> Load the script tag. Reactivity works alongside jQuery.</li><li><strong>Custom architecture?</strong> Load the script tag. Keep your structure.</li></ul><p>No migration. No refactoring. No forced patterns. Just reactivity.</p><h3 id="freedom-of-style" tabindex="-1">Freedom of Style <a class="header-anchor" href="#freedom-of-style" aria-label="Permalink to “Freedom of Style”">​</a></h3><p>DOM Helpers Reactive respects your preferences:</p><ul><li>Write imperative code if you prefer</li><li>Write declarative code if you prefer</li><li>Mix both styles freely</li><li>Use your own naming conventions</li><li>Structure your code your way</li></ul><p>The library provides reactive power without dictating how you use it.</p><h3 id="preserve-the-connection" tabindex="-1">Preserve the Connection <a class="header-anchor" href="#preserve-the-connection" aria-label="Permalink to “Preserve the Connection”">​</a></h3><p>The creator&#39;s core belief: <strong>developers should never lose touch with the DOM.</strong> Every abstraction in DOM Helpers Reactive is transparent and optional. You can always drop down to direct manipulation. You always know what&#39;s happening under the hood.</p><h2 id="the-dom-helpers-ecosystem" tabindex="-1">The DOM Helpers Ecosystem <a class="header-anchor" href="#the-dom-helpers-ecosystem" aria-label="Permalink to “The DOM Helpers Ecosystem”">​</a></h2><h3 id="dom-helpers-core-the-foundation" tabindex="-1">DOM Helpers Core: The Foundation <a class="header-anchor" href="#dom-helpers-core-the-foundation" aria-label="Permalink to “DOM Helpers Core: The Foundation”">​</a></h3><p><strong>DOM Helpers Core</strong>— is the main module of the DOM Helpers library. Core provides powerful, declarative DOM manipulation features with a rich set of capabilities. It represents my vision for what vanilla DOM manipulation should feel like: expressive, intuitive, declarative and powerful.</p><h3 id="dom-helpers-reactive-independent-yet-integrated" tabindex="-1">DOM Helpers Reactive: Independent Yet Integrated <a class="header-anchor" href="#dom-helpers-reactive-independent-yet-integrated" aria-label="Permalink to “DOM Helpers Reactive: Independent Yet Integrated”">​</a></h3><p><strong>DOM Helpers library</strong> provides also a reactivy system The reactive system is <strong>completely independent</strong>. It stands alone as a full-featured reactivity solution. You can use it without Core, and it works beautifully on its own.</p><p>But when combined with Core, something remarkable happens: <strong>you get reactivity plus powerful declarative DOM manipulation.</strong></p><p>The synergy creates an environment where:</p><ul><li>State changes automatically update the UI (Reactive)</li><li>DOM manipulation is expressive and elegant (Core)</li><li>Everything works in pure vanilla JavaScript</li><li>No framework lock-in</li><li>No heavy abstractions</li><li>Complete control</li></ul><h3 id="two-modes-of-power" tabindex="-1">Two Modes of Power <a class="header-anchor" href="#two-modes-of-power" aria-label="Permalink to “Two Modes of Power”">​</a></h3><p><strong>Using Reactive Alone:</strong></p><ul><li>Powerful reactivity features</li><li>State management</li><li>Automatic UI synchronization</li><li>Minimal footprint</li><li>Works with any DOM manipulation approach</li></ul><p><strong>Using Reactive + Core Together:</strong></p><ul><li>All reactivity features</li><li>Rich declarative DOM manipulation</li><li>Seamless integration between state and DOM</li><li>Incredible power and expressiveness</li><li>Still pure vanilla JavaScript</li></ul><h2 id="the-mission" tabindex="-1">The Mission <a class="header-anchor" href="#the-mission" aria-label="Permalink to “The Mission”">​</a></h2><p>DOM Helpers Reactive exists to prove that <strong>you don&#39;t need to abandon vanilla JavaScript to have modern reactivity.</strong> You don&#39;t need framework abstractions. You don&#39;t need to give up control. You don&#39;t need to forget how the DOM works.</p><p>You just need the right tool—one that enhances rather than replaces, one that empowers rather than abstracts, one that respects your skills rather than hiding them.</p><h3 id="for-developers-who" tabindex="-1">For Developers Who: <a class="header-anchor" href="#for-developers-who" aria-label="Permalink to “For Developers Who:”">​</a></h3><ul><li>Love vanilla JavaScript</li><li>Want to understand what&#39;s happening</li><li>Prefer control over convenience</li><li>Value learning over magic</li><li>Need flexibility over structure</li><li>Want reactivity without compromise</li></ul><h2 id="looking-forward" tabindex="-1">Looking Forward <a class="header-anchor" href="#looking-forward" aria-label="Permalink to “Looking Forward”">​</a></h2><p>The vision continues to evolve, guided by the same principles:</p><ol><li><strong>Keep it simple</strong> - Complexity should be optional, not mandatory</li><li><strong>Stay transparent</strong> - Developers should always understand what&#39;s happening</li><li><strong>Remain flexible</strong> - Never force architectural decisions</li><li><strong>Preserve fundamentals</strong> - JavaScript skills should grow, not atrophy</li><li><strong>Deliver power</strong> - Provide capabilities that rival any framework</li></ol><p>DOM Helpers Reactive isn&#39;t just a library—it&#39;s a statement that vanilla JavaScript, when properly empowered, remains the most exciting and capable way to build for the web.</p><h2 id="the-creator-s-note" tabindex="-1">The Creator&#39;s Note <a class="header-anchor" href="#the-creator-s-note" aria-label="Permalink to “The Creator&#39;s Note”">​</a></h2><blockquote><p>&quot;I built this because I missed the DOM. I missed knowing exactly what was happening. I missed the excitement of direct manipulation. But I didn&#39;t want to give up manual dom manipulation. So I built something that let me have both—and I built it so you could have both too, on your terms, in your style, in your projects.&quot;</p><p>— Giovanni S. Marianne Creator of DOM Helpers Reactive</p></blockquote><p><em>DOM Helpers: Bringing power back to vanilla JavaScript, one feature at a time.</em></p>',58)])])}const g=a(n,[["render",l]]);export{m as __pageData,g as default};
